module RefModule (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] S,
    output Cout
);
    wire [3:0] obf_P; // Propagate
    wire [3:0] G; // Generate
    wire [4:0] C; // Carry

    assign obf_P = A ^ B; // Propagate
    assign G = A & B; // Generate

    assign C[0] = Cin; // Carry-in
    assign C[1] = G[0] | (obf_P[0] & C[0]);
    assign C[2] = G[1] | (obf_P[1] & C[1]);
    assign C[3] = G[2] | (obf_P[2] & C[2]);
    assign C[4] = G[3] | (obf_P[3] & C[3]);

    assign S = obf_P ^ C[3:0]; // Sum
    assign Cout = C[4]; // Carry-out
endmodule
